import React, { useState, useEffect } from "react";

const StudentDashboard = () => {
  const [student, setStudent] = useState({});
  const [mentors, setMentors] = useState([]);
  const [selectedMentor, setSelectedMentor] = useState("");
  const [projectTitle, setProjectTitle] = useState("");
  const [domain, setDomain] = useState("");
  const [timeRequired, setTimeRequired] = useState("");
  const [description, setDescription] = useState("");
  const [error, setError] = useState("");
  const [successMsg, setSuccessMsg] = useState("");

  const token = localStorage.getItem("token");

  // 🟠 Fetch student info and mentors
  useEffect(() => {
    const fetchStudentInfo = async () => {
      try {
        const res = await fetch("http://localhost:5050/api/students/me", {
          headers: { Authorization: `Bearer ${token}` },
        });
        if (!res.ok) {
          const errData = await res.json();
          console.error("Student info error:", errData);
          setError("Failed to load student info");
          return;
        }
        const data = await res.json();
        setStudent(data);
      } catch (err) {
        console.error("Error fetching student info:", err);
        setError("Server error while fetching student info");
      }
    };

    const fetchMentors = async () => {
      try {
        const res = await fetch("http://localhost:5050/api/students/mentors", {
          headers: { Authorization: `Bearer ${token}` },
        });
        if (!res.ok) {
          const errData = await res.json();
          console.error("Mentor fetch error:", errData);
          setError("Failed to load mentors");
          return;
        }
        const data = await res.json();
        setMentors(data);
      } catch (err) {
        console.error("Error fetching mentors:", err);
        setError("Server error while fetching mentors");
      }
    };

    if (token) {
      fetchStudentInfo();
      fetchMentors();
    } else {
      setError("Access token missing. Please log in again.");
    }
  }, [token]);

  // 🟢 Submit project request
  const handleProjectSubmit = async (e) => {
    e.preventDefault();
    setError("");
    setSuccessMsg("");

    if (!selectedMentor || !projectTitle) {
      setError("Please select a mentor and enter project details.");
      return;
    }

    try {
      const res = await fetch("http://localhost:5050/api/students/request", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${token}`,
        },
        body: JSON.stringify({
          student_id: student.sno,
          mentor_id: selectedMentor,
          project_title: projectTitle,
          description,
          domain,
          time_required: timeRequired,
        }),
      });

      const data = await res.json();
      if (!res.ok) {
        console.error("Project request error:", data);
        setError(data.error || "Error submitting project request");
        return;
      }

      setSuccessMsg("Project request submitted successfully!");
      setSelectedMentor("");
      setProjectTitle("");
      setDomain("");
      setTimeRequired("");
      setDescription("");
    } catch (err) {
      console.error("Error submitting project:", err);
      setError("Server error while submitting project");
    }
  };

  // 🟢 Logout
  const handleLogout = () => {
    localStorage.removeItem("token");
    localStorage.removeItem("role");
    window.location.href = "/login";
  };

  return (
    <div className="student-dashboard">
      <div className="header">
        <h1>Hello, {student.studentname || "Student"}</h1>
        <button className="logout-btn" onClick={handleLogout}>
          Logout
        </button>
      </div>

      {error && <p className="error-banner">{error}</p>}
      {successMsg && <p className="success-banner">{successMsg}</p>}

      <div className="dashboard-content">
        {/* Student Info */}
        <div className="student-info card">
          <h3>Your Info</h3>
          <p><strong>Reg No:</strong> {student.registerationno}</p>
          <p><strong>Email:</strong> {student.Email}</p>
          <p><strong>Semester:</strong> {student.semester}</p>
          <p><strong>Batch:</strong> {student.batch}</p>
        </div>

        {/* Mentor Cards */}
        <div className="mentors-section card">
          <h3>Available Mentors</h3>
          {mentors.length > 0 ? (
            <div className="mentor-list">
              {mentors.map((m) => (
                <div key={m.sno} className="mentor-card">
                  <h4>{m.name}</h4>
                  <p><strong>Specialization:</strong> {m.specialization || "N/A"}</p>
                  <p><strong>Email:</strong> {m.email}</p>
                </div>
              ))}
            </div>
          ) : (
            <p>No mentors available yet.</p>
          )}
        </div>

        {/* Project Form */}
        <div className="project-section card">
          <h3>Submit Project Idea</h3>
          <form onSubmit={handleProjectSubmit}>
            <select
              value={selectedMentor}
              onChange={(e) => setSelectedMentor(e.target.value)}
              required
            >
              <option value="">Select Mentor</option>
              {mentors.map((m) => (
                <option key={m.sno} value={m.sno}>
                  {m.name}
                </option>
              ))}
            </select>

            <input
              type="text"
              placeholder="Project Title"
              value={projectTitle}
              onChange={(e) => setProjectTitle(e.target.value)}
              required
            />

            <input
              type="text"
              placeholder="Domain"
              value={domain}
              onChange={(e) => setDomain(e.target.value)}
            />

            <input
              type="text"
              placeholder="Time Required"
              value={timeRequired}
              onChange={(e) => setTimeRequired(e.target.value)}
            />

            <textarea
              placeholder="Project Description"
              value={description}
              onChange={(e) => setDescription(e.target.value)}
            ></textarea>

            <button type="submit" className="submit-btn">
              Submit Request
            </button>
          </form>
        </div>
      </div>
    </div>
  );
};

export default StudentDashboard;
